@@ -68,0 +68,3 @@
+ * - I'm also mixing signed and unsigned comparisons, just to ensure
+ *   the less often used (and tested) unsigned comparisons don't slip
+ *   through the cracks.
@@ -128,6 +131,12 @@
-        LT(" < "),
-        LE(" <= "),
-        GT(" > "),
-        GE(" >= "),
-        EQ(" == "),
-        NE(" != ");
+        ULT(" <  0", false),
+        ULE(" <= 0", false),
+        UGT(" >  0", false),
+        UGE(" >= 0", false),
+        UEQ(" == 0", false),
+        UNE(" != 0", false),
+        LT(" <  ", true),
+        LE(" <= ", true),
+        GT(" >  ", true),
+        GE(" >= ", true),
+        EQ(" == ", true),
+        NE(" != ", true);
@@ -136,0 +145,1 @@
+        private final boolean signed;
@@ -137,1 +147,1 @@
-        Comparator(String token) {
+        Comparator(String token, boolean signed) {
@@ -139,0 +149,1 @@
+            this.signed = signed;
@@ -145,0 +156,4 @@
+        public boolean isSigned() {
+            return signed;
+        }
+
@@ -147,0 +162,6 @@
+                case ULT -> UGE;
+                case ULE -> UGT;
+                case UGT -> ULE;
+                case UGE -> ULT;
+                case UEQ -> UNE;
+                case UNE -> UEQ;
@@ -158,0 +179,6 @@
+                case ULT -> UGT;
+                case ULE -> UGE;
+                case UGT -> ULT;
+                case UGE -> ULE;
+                case UEQ -> UEQ;
+                case UNE -> UNE;
@@ -186,1 +213,3 @@
-            return (negated ? "!" : "") + "(" + lhs + " "+ cmp.getToken() + " " + rhs + ")";
+            return cmp.isSigned()
+                ? ((negated ? "!" : "") + "(" + lhs + " "+ cmp.getToken() + " " + rhs + ")")
+                : ((negated ? "!" : "") + "(Integer.compareUnsigned(" + lhs + ", " + rhs + ")" + cmp.getToken() + ")");
